ee:message.ee:set-payload:
%dw 2.0  
output text/plain  

import * from dw::core::Strings  

var e = payload.event  

// Helper Functions  
// Helper Functions
fun mustHave(val) = if (val == null or val == "") "" else val

// HL7 IDs  
var rawPid = mustHave(e.Patient_ID__c)
var pid = if((upper(rawPid) startsWith "HF")) rawPid[2 to -1] else rawPid  

var lastName = mustHave(e.Patient_Last_Name__c)
var firstName = mustHave(e.Patient_First_Name__c)
var dobNum = mustHave(e.Patient_DOB__c)
var dob = ((dobNum as Number) as Date) as String {format: "yyyyMMdd"}  

var genderRaw = mustHave(e.Patient_Gender__c)
var hl7Gender =   
    if (upper(genderRaw) == "FEMALE" or upper(genderRaw) == "F") "F"  
    else if (upper(genderRaw) == "MALE" or upper(genderRaw) == "M") "M"  
    else "U"  

var providerNpi = mustHave(e.Provider_NPI__c)
var providerLast = mustHave(e.Provider_Last_Name__c)
var providerFirst = mustHave(e.Provider_First_Name__c)
var locationId = mustHave(e.Location_ID__c)
var locationName = mustHave(e.Location_Name__c)

var schPlacer = mustHave(e.Placer_Appointment_ID__c)

var schFiller = if (e.NextGen_ID__c != null and e.NextGen_ID__c != "") e.NextGen_ID__c   
                else schPlacer  

var apptType = mustHave(e.Appointment_Type__c)
var apptReason = mustHave(e.Appointment_Reason__c)
var duration = mustHave(e.Duration_Value__c)

var startEpoch = mustHave(e.Start_DateTime__c) as Number
var endEpoch = mustHave(e.End_DateTime__c) as Number
var schStart = (startEpoch as DateTime) as String {format:"yyyyMMddHHmmss"}  
var schEnd = (endEpoch as DateTime) as String {format:"yyyyMMddHHmmss"}  

// Patient Address  
var street = mustHave(e.Patient_Street__c)
var city = mustHave(e.Patient_City__c)
var state = mustHave(e.Patient_State__c)
var zip = mustHave(e.Patient_Zip__c)

// Language: fallback to EN per HL7 spec for NextGen - but you can error if really required  
var language = e.Patient_Language__c default "EN"  

// Phone Formatting  
var phone = mustHave(e.Patient_Phone__c)
var area = phone[0 to 2]  
var rest = phone[3 to 9]  
var phoneFormatted = "(" ++ area ++ ")" ++ rest[0 to 2] ++ "-" ++ rest[3 to 6]  

var pid13 =   
    if (sizeOf(phone) == 10 and phone ~= /[0-9]{10}/)  
        phoneFormatted ++ "^^^^^" ++ area ++ "^" ++ rest  
    else  
                ""

// Status (always NEW for S12)  
var status = "NEW"  

---  
(  
"MSH|^~\\&|HEALTHFUSION^1266378|NEXTGENOFFICE^1266378|FORESTHMS|FORESTHMS^1266378|" ++  
(now() as String {format:"yyyyMMddHHmmss"}) ++  
"||SIU^S12|" ++ schFiller ++ "|P|2.3" ++  
"\nSCH|" ++ schPlacer ++ "|" ++ schFiller ++ "||||" ++ apptType ++ "|" ++ apptReason ++ "|" ++ apptType ++ "|" ++ duration ++ "|MIN|^^^" ++ schStart ++ "^" ++ schEnd ++ "|||||" ++ providerNpi ++ "^" ++ providerLast ++ "^" ++ providerFirst ++ "|||||||||" ++ status ++  
"\nPID|1|" ++ pid ++ "|" ++ pid ++ "|HF" ++ pid ++ "|" ++ upper(lastName) ++ "^" ++ upper(firstName) ++ "||" ++ dob ++ "|" ++ hl7Gender ++ "||PATIENT DECLINED|" ++ street ++ "^^" ++ upper(city) ++ "^" ++ upper(state) ++ "^" ++ zip ++ "|" ++ pid13 ++ "||" ++ language ++ "|||||||PATIENT DECLINED" ++  
"\nPV1|1|O|^^^" ++ locationId ++ "^^^^^" ++ upper(locationName) ++ "||||" ++ providerNpi ++ "^" ++ providerLast ++ "^" ++ providerFirst ++ "||||1275017^^^1275017^^^^^FOREST HILLS||||||||" ++ schFiller ++ "||||||||||||||||||||1266378;FOREST HILLS MEDICAL SERVICES;FORESTHMS|||||" ++ schStart ++ "|" ++ schEnd ++  
"\nRGS|" ++  
"\nAIL|1||" ++ locationId ++ "^^^" ++ upper(locationName) ++  
"\nAIP|1||" ++ providerNpi ++ "^" ++ providerLast ++ "^" ++ providerFirst  
)

%dw 2.0  
output text/plain  

var pe = payload.event  

var apptId        = (pe.NextGen_ID__c default "") as String  
var pidRaw        = (pe.Patient_ID__c default "") as String  
var pid           = if (upper(pidRaw) startsWith "HF") pidRaw[2 to -1] else pidRaw  

// DOB: Now a Date number  
var dob           = (pe.Patient_DOB__c as Date) as String {format:"yyyyMMdd"}  

// Gender  
var genderRaw     = (pe.Patient_Gender__c default "") as String  
var gender =  
  if (genderRaw == "Female") "F"  
  else if (genderRaw == "Male") "M"  
  else "U"  

// --- PHONE NUMBER SECTION ---  
var phone         = (pe.Patient_Phone__c default "") as String  
var isGoodPhone   = sizeOf(phone) == 10 and phone ~= /[0-9]{10}/  
var phoneFormatted = if (isGoodPhone)  
    "(" ++ phone[0 to 2] ++ ")" ++ phone[3 to 5] ++ "-" ++ phone[6 to 9]  
  else  
    phone  
var area  = if (isGoodPhone) phone[0 to 2] else ""  
var rest  = if (isGoodPhone) phone[3 to 9] else ""  
var contactInfo = if (isGoodPhone)  
    phoneFormatted ++ "^^^" ++ "^^" ++ area ++ "^" ++ rest  
  else  
    phone ++ "^^^^^^"  
// --------------------------------------  

// Status  
var statusRaw     = (pe.Appointment_Status__c default "") as String  
var status =  
  if (statusRaw == "Cancelled by Provider") "CANCELLED"  
  else if (statusRaw == "No Show") "NO SHOW"  
  else if (statusRaw == "RESCHEDULED") "RESCHEDULED"  
  else if (statusRaw == "Checked Out") "CHECKED OUT"  
  else if (statusRaw == "Checked In") "CHECKED IN"  
  else if (statusRaw == "Scheduled") "NEW"  
  else statusRaw  

// Start/End as DateTime numbers (epoch ms)  
var schStart      = pe.Start_DateTime__c as DateTime  
var schStartStr   = (schStart as String {format:"yyyyMMddHHmmss"})  
var schEnd        = pe.End_DateTime__c as DateTime  
var schEndStr     = (schEnd as String {format:"yyyyMMddHHmmss"})  

var providerNpi   = (pe.Provider_NPI__c default "") as String  
var providerLast  = upper((pe.Provider_Last_Name__c default "") as String)  
var providerFirst = upper((pe.Provider_First_Name__c default "") as String)  
var apptType      = upper((pe.Appointment_Type__c default "") as String)  
var apptReason    = (pe.Appointment_Reason__c default "") as String  
var locationId    = (pe.Location_ID__c default "") as String  
var locationName  = upper((pe.Location_Name__c default "") as String)  
var patientLast   = upper((pe.Patient_Last_Name__c default "") as String)  
var patientFirst  = upper((pe.Patient_First_Name__c default "") as String)  
var language      = upper((pe.Patient_Language__c default "EN") as String)  
var patientStreet = upper((pe.Patient_Street__c default "") as String)  
var patientCity   = upper((pe.Patient_City__c default "") as String)  
var patientState  = upper((pe.Patient_State__c default "") as String)  
var patientZip    = upper((pe.Patient_Zip__c default "") as String)  
var durationRaw   = (pe.Duration_Value__c default "") as String  

---  
(  
  "MSH|^~\\&|HEALTHFUSION^1266378|NEXTGENOFFICE^1266378|FORESTHMS|FORESTHMS^1266378|" ++  
  now() as String {format:"yyyyMMddHHmmss"} ++  
  "||SIU^S15|" ++ apptId ++ "|P|2.3" ++  

  "\nSCH||" ++ apptId ++ "||||" ++ apptType ++ "|" ++ apptReason ++ "|" ++ apptType ++ "|" ++ durationRaw ++ "|MIN|" ++ "^^^" ++ schStartStr ++ "^" ++ schEndStr ++ "|||||" ++ providerNpi ++ "^" ++ providerLast ++ "^" ++ providerFirst ++ "|||||||||" ++ status ++  

  "\nPID|1|" ++ pid ++ "|" ++ pid ++ "|HF" ++ pid ++ "|" ++ patientLast ++ "^" ++ patientFirst ++ "|" ++ "|" ++ dob ++ "|" ++ gender ++ "|" ++ "|" ++ "PATIENT DECLINED|" ++ patientStreet ++ "^^" ++ patientCity ++ "^" ++ patientState ++ "^" ++ patientZip ++ "|" ++ contactInfo ++ "||" ++ language ++ "|||||||PATIENT DECLINED" ++  

  "\nPV1|1|O|^^^" ++ locationId ++ "^^^^^" ++ locationName ++ "||||" ++ providerNpi ++ "^" ++ providerLast ++ "^" ++ providerFirst ++ "||||1275017^^^1275017^^^^^FOREST HILLS||||||||" ++ apptId ++ "||||||||||||||||||||1266378;FOREST HILLS MEDICAL SERVICES;FORESTHMS|||||" ++ schStartStr ++ "|" ++ schEndStr ++  

  "\nRGS|" ++  

  "\nAIL|1||" ++ locationId ++ "^^^" ++ locationName ++  

  "\nAIP|1||" ++ providerNpi ++ "^" ++ providerLast ++ "^" ++ providerFirst  
)
